var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아아- 이번에도 C급이라니. 나이엘 앞에선 아무렇지 않은 척했지만 역시 아쉽다.","JPN":"あーあー、今回もC級だなんて。ナイエルの前では何でもないふりしたけど、やっぱり気にしちゃうな。","ENG":"Ahh... Grade C again? I acted like I didn't care in front of Naielle, but it's pretty upsetting.","TWN":"可惡，這次還是C，雖然在奈爾面前裝作不在意，但還是有點難過。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"하지만 괜찮아! 내년에는 다른 결과가 나올지도 모르니까!","JPN":"でも大丈夫！　来年はまた結果が変わっているかもしれないんだし！","ENG":"But it's okay! Because next year's results could be better!","TWN":"沒關係！明年說不定會有不一樣的結果！"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"카운터 등급이라는 것은… 수행에 따라 변하기도 하는 것이오?","JPN":"カウンターのランクって……修行することで変わることもあるのでしょうか？","ENG":"This Counter grade... does it change depending on your training?","TWN":"所謂的制裁者等級…是靠著修行就能夠改變的嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"물론이지! 세상엔 노력으로 바뀌지 않는 건 없어!","JPN":"もちろんだよ！　この世に努力で変えられないものはないんだから！","ENG":"Of course! There's nothing in this world that hard work can't change!","TWN":"那當然！世界上沒有什麼事是無法靠著努力改變的！"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"…라고 말하고 싶지만, 확신은 못하겠네.","JPN":"……って言いたいところだけど、確信はないかも。","ENG":"...Is what I want to believe, but I'm not actually sure.","TWN":"…我也很想這麼說，但事實是不一定。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"시간에 따라 힘이 꾸준히 성장하는 케이스도 있지만, 그렇지 않은 케이스가 훨씬 많거든.","JPN":"時間の経過とともに、着実に能力が成長していくパターンもあるけど、そうでないことの方が多いからね。","ENG":"There are cases where their powers steadily get more powerful, but there are even more cases where they don't.","TWN":"有些人的能力是會隨著時間而進步，但絕大部分的人好像都不是這樣。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"카운터인 우리도 정작 자신의 힘을 전부 이해하지 못해. 카운터의 능력에 대한 연구는 아직도 한창 진행 중이니까.","JPN":"カウンターのあたしたちですら、自分たちの力の全てを理解しているわけじゃない。カウンターの能力に関する研究はまだまだ発展途上なの。","ENG":"I mean, we're Counters, and we don't fully understand our abilities either. Experts are still researching it.","TWN":"就連身為制裁者的我們，都還無法完全知道自己的能力到哪裡，因為有關制裁者能力的研究都還在進行中。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"아카데미의 학생들이 전광판의 기록에 일희일비 하는 모습을 보았소.","JPN":"アカデミーの生徒たちが電光板の記録に一喜一憂するところを見ました。","ENG":"I saw how the students got emotional about the records on the scoreboard.","TWN":"在下看到學院的學生因為螢幕上的紀錄而患得患失。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그 결과 하나가 많은 의미가 담긴 것처럼 느껴졌다오.","JPN":"あの結果が、とても大きな意味を持っていることがわかります。","ENG":"I could sense that each result had a lot of meaning to it.","TWN":"雖然只是一個結果，似乎卻代表著許多含意。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"세상일이라는 게 다 그렇잖아? 알파벳 같은 성적 하나로 주위의 시선이나 평가가 바뀌거든.","JPN":"それが世の常というものでしょう？ただのアルファベット一つで、周りからの視線や評価がひっくり返るからね。","ENG":"That's how the world works, right? People treat us differently depending on which alphabet we get.","TWN":"世界不就是這樣嗎？因為那些代表成績的英文字母，可以改變人家對你的眼光和評價。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"이면세계에 나가는 사람들도, 침식재난을 마주친 사람들도, 우리 같은 C급 카운터보단 A급 카운터와 함께 있는 편이 마음 편할 테니까.","JPN":"裏世界に赴く人たちも、侵食災害に見舞われた人たちも、あたしたちみたいなC級より、A級カウンターが一緒にいた方が心強いだろうしね。","ENG":"People who go to Counterside, and others who have encountered a Corruption disaster... they'd want to have a Grade A Counter by their side rather than a Grade C like us.","TWN":"不管是去到異界，或是面對侵蝕災難時，比起我們這種C級的，大家跟A級在一起比較安心吧。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐어- 아쉬운 건 아쉬운 거지만. 그렇다고 너무 좌절할 필요는 없다고 생각해.","JPN":"まぁ、やるせないといえばそうだけど。そこで挫折することはないと思うな。","ENG":"Well, such is life. But I don't think we need to get frustrated about it so much.","TWN":"算啦～難過是有點難過，但也不需要因此而感到太挫折。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"학생회장님이 말했어. 아카데미가 학생들을 가르치는 목적은 카운터 등급을 높이는 게 아니라 그 사람이 가장 원하는 꿈을 찾아주는 거라고 말이야.","JPN":"生徒会長も言ってたよ。アカデミーが生徒たちを教える目的は、カウンターランクの上昇ではなく、それぞれが夢を見つけられるようサポートするためだって。","ENG":"Ms. President once said to me, that the purpose of teaching students at the Academy isn't to improve their Counter Grades, but to help them find and achieve their dreams.","TWN":"學生會長說過，學院的目的不是把學生教成很厲害的制裁者，而是幫助學生找到夢想。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"난 그 말이 밤에 빛나는 별처럼 마음에 와닿았어.","JPN":"あたしはその言葉が、すごくキラキラした星のように思えたの。","ENG":"What she told me stuck with me, and it has been guiding me like a star shining brightly in the night sky.","TWN":"那番話如同夜空中閃耀的星星那般觸動我。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그래서 학생회장과 함께 다른 친구들의 꿈을 이끌어주고 싶다는 마음으로 학생회 임원이 된 거야. 내 능력과는 별개로.","JPN":"だからあたしは生徒会長と一緒に、他のみんなの夢をサポートしてあげたいと思って、生徒会役員になったんだ。自分にその能力があるかどうかじゃなくてね。","ENG":"It's also why I decided to join the Student Council. I wanted to help my friends find their dreams, regardless of my abilities.","TWN":"所以我會當學生會幹部，與我的能力無關，是因為我想和學生會長一起幫助學生找到夢想。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아하하… 다 말하고 나니 쑥스럽네. 혼자만 신나서 너무 떠들었나?","JPN":"あはは……つい語っちゃった。ちょっと夢中になりすぎたかな？","ENG":"Ah ha ha... Saying it out loud is kinda embarrassing. Did I get too excited and start rambling?","TWN":"哈哈哈…說完自己都覺得有點害羞呢，我是不是自顧自地說得太開心啦？"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그대의 마음은 분명 사람들을 올바른 길로 이끌 거요. 본인이 장담하오.","JPN":"貴殿の想いはきっと人々を正しい道に導くでしょう。自分が保証します。","ENG":"Your heart will lead people down the right path. I am certain of it.","TWN":"相信你的心一定可以引導學生走在正路，在下保證。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};